        // Adding elements to the HashMap
        myMap.put("one", new MyClass("Banana"));
        myMap.put("two", new MyClass("Apple"));

        // Accessing an element
        MyClass myClass = myMap.get("one");
        System.out.println("Retrieved from map: " + myClass);
