```java
import java.io.*;
import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;

// EnergySector Class
class EnergySector implements Serializable {
    private static final long serialVersionUID = 1L;
    private String name;
    private Map<String, Double> demand; // Region and its demand

    public EnergySector(String name) {
        this.name = name;
        this.demand = new HashMap<>();
    }

    public String getName() {
        return name;
    }

    public Map<String, Double> getDemand() {
        return demand;
    }

    public void setDemand(String region, double value) {
        demand.put(region, value);
    }

    // Method to get total demand for this sector
    public double getTotalDemand() {
        return demand.values().stream().mapToDouble(Double::doubleValue).sum();
    }
}

// Factory Class for EnergySector Creation
class EnergySectorFactory {
    public static EnergySector createEnergySector(String type) {
        switch (type.toLowerCase()) {
            case "solar":
                return new EnergySector("Solar");
            case "wind":
                return new EnergySector("Wind");
            case "gas":
                return new EnergySector("Gas");
            default:
                throw new IllegalArgumentException("Unknown energy type: " + type);
        }
    }
}

// EnergyDemandModel Class
class EnergyDemandModel implements Serializable {
    private static final long serialVersionUID = 1L;
    private Map<String, EnergySector> sectors;

    public EnergyDemandModel() {
        this.sectors = new HashMap<>();
    }

    public void addSector(EnergySector sector) {
        sectors.put(sector.getName(), sector);
    }

    public double getTotalDemand() {
        return sectors.values().stream().mapToDouble(EnergySector::getTotalDemand).sum();
    }

    public void saveToFile(String filename) throws IOException {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(filename))) {
            oos.writeObject(this);
        }
    }

    public static EnergyDemandModel loadFromFile(String filename) throws IOException, ClassNotFoundException {
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(filename))) {
            return (EnergyDemandModel) ois.readObject();
        }
    }
}

// Main Class for User Interaction
public class Main {
    private static final Scanner scanner = new Scanner(System.in);

    public static void main(String[] args) {
        EnergyDemandModel model = new EnergyDemandModel();
        String command;

        do {
            System.out.println("Enter command (add, total, save, load, exit): ");
            command = scanner.nextLine().toLowerCase();
            handleCommand(command, model);
        } while (!command.equals("exit"));

        scanner.close();
    }

    private static void handleCommand(String command, EnergyDemandModel model) {
        switch (command) {
            case "add":
                addSector(model);
                break;

            case "total":
                System.out.println("Total demand across all sectors: " + model.getTotalDemand() + " MW");
                break;

            case "save":
                saveModel(model);
                break;

            case "load":
                loadModel(model);
                break;

            case "exit":
                System.out.println("Exiting...");
                break;

            default:
                System.out.println("Unknown command.");
        }
    }

    private static void addSector(EnergyDemandModel model) {
        System.out.println("Enter energy type (Solar, Wind, Gas): ");
        String type = scanner.nextLine();
        try {
            EnergySector sector = EnergySectorFactory.createEnergySector(type);
            System.out.println("Enter region: ");
            String region = scanner.nextLine();
            System.out.println("Enter demand (MW): ");
            double demandValue = validateDemand();
            sector.setDemand(region, demandValue);
            model.addSector(sector);
            System.out.println("Sector added successfully.");
        } catch (IllegalArgumentException e) {
            System.err.println(e.getMessage());
        }
    }

    private static double validateDemand() {
        while (true) {
            try {
                String input = scanner.nextLine();
                double value = Double.parseDouble(input);
                if (value < 0) {
                    throw new NumberFormatException("Demand cannot be negative.");
                }
                return value;
            } catch (NumberFormatException e) {
                System.err.println("Invalid input. Please enter a valid positive number for demand (MW): ");
            }
        }
    }

    private static void saveModel(EnergyDemandModel model) {
        try {
            model.saveToFile("energyDemandModel.dat");
            System.out.println("Model saved.");
        } catch (IOException e) {
            System.err.println("Error saving model: " + e.getMessage());
        }
    }

    private static void loadModel(EnergyDemandModel model) {
        try {
            model = EnergyDemandModel.loadFromFile("energyDemandModel.dat");
            System.out.println("Model loaded.");
        } catch (IOException | ClassNotFoundException e) {
            System.err.println("Error loading model: " + e.getMessage());
        }
    }
}
```

