import React, { useState } from 'react';

const ConfirmModal = ({ isOpen, onConfirm, onCancel }) => {
    if (!isOpen) return null;

    return (
        <div className="modal">
            <h2>Are you sure?</h2>
            <button onClick={onConfirm}>Yes</button>
            <button onClick={onCancel}>No</button>
        </div>
    );
};

const App = () => {
    const [isModalOpen, setIsModalOpen] = useState(false);

    const handleDeleteClick = () => {
        setIsModalOpen(true);
    };

    const handleConfirm = () => {
        console.log("Action confirmed. Proceed with deletion.");
        setIsModalOpen(false);
        // Call your deletion logic here
    };

    const handleCancel = () => {
        console.log("Action canceled. No deletion performed.");
        setIsModalOpen(false);
    };

    return (
        <div>
            <button onClick={handleDeleteClick}>Delete Item</button>
            <ConfirmModal isOpen={isModalOpen} onConfirm={handleConfirm} onCancel={handleCancel} />
        </div>
    );
};

export default App;
```

### Conclusion
This approach provides a clean way to manage user confirmations in JavaScript applications. If you have a specific framework or library in mind, please let me know, and I can tailor the example to fit that context!

